                  whileTap={{ scale: 0.97 }}
                  style={outlineBtn}
                  onClick={handleBack}
                >
                  {selectedFamilyId ? "Back" : "Cancel"}
                </motion.button>
                {selectedFamilyId && (
                  <motion.button
                    whileHover={{
                      scale: selectedSpecGroups.size > 0 ? 1.02 : 1,
                    }}
                    whileTap={{ scale: selectedSpecGroups.size > 0 ? 0.97 : 1 }}
                    onClick={handleContinue}
                    disabled={selectedSpecGroups.size === 0}
                    style={{
                      padding: "9px 20px",
                      borderRadius: 10,
                      border: "none",
                      background:
                        selectedSpecGroups.size > 0
                          ? TOKEN.primary
                          : TOKEN.border,
                      color:
                        selectedSpecGroups.size > 0 ? "#fff" : TOKEN.textSec,
                      fontSize: 13,
                      fontWeight: 700,
                      cursor:
                        selectedSpecGroups.size > 0 ? "pointer" : "not-allowed",
                      display: "inline-flex",
                      alignItems: "center",
                      gap: 6,
                      opacity: selectedSpecGroups.size === 0 ? 0.5 : 1,
                    }}
                  >
                    Continue
                  </motion.button>
                )}
              </div>
            </motion.div>
          </div>
        </>
      )}
    </AnimatePresence>
  );
}

